1	//! Rust Pipeline view component - Wizard-driven 3-column layout
2	//! Shows the compilation pipeline: Rust -> MSP430 ASM -> COR24 ASM -> Machine Code -> Execution
3	
4	use std::cell::Cell;
5	use std::rc::Rc;
6	
7	use yew::prelude::*;
8	
9	use crate::DebugPanel;
10	
11	/// Pre-built example for the Rust pipeline demo
12	#[derive(Clone, PartialEq)]
13	pub struct RustExample {
14	    pub name: String,
15	    pub description: String,
16	    pub rust_source: String,
17	    pub msp430_asm: String,
18	    pub cor24_assembly: String,
19	}
20	
21	/// Sparse memory representation: only non-zero 16-byte rows within a region.
22	/// The display renders summary lines for zero gaps between non-zero rows.
23	#[derive(Clone, PartialEq, Default)]
24	pub struct SparseMemory {
25	    pub region_start: u32, // First address of the region
26	    pub region_end: u32,   // Last address + 1 (exclusive)
27	    /// Non-zero rows: (row_start_address, 16 bytes). Sorted by address.
28	    pub rows: Vec<(u32, Vec<u8>)>,
29	}
30	
31	impl SparseMemory {
32	    /// Build from a byte slice representing memory at `base_addr..base_addr+data.len()`.
33	    pub fn from_slice(data: &[u8], base_addr: u32) -> Self {
34	        let mut rows = Vec::new();
35	        for (i, chunk) in data.chunks(16).enumerate() {
36	            if chunk.iter().any(|&b| b != 0) {
37	                rows.push((base_addr + (i * 16) as u32, chunk.to_vec()));
38	            }
39	        }
40	        SparseMemory {
41	            region_start: base_addr,
42	            region_end: base_addr + data.len() as u32,
43	            rows,
44	        }
45	    }
46	}
47	
48	/// CPU state for display in the Rust pipeline execution panel
49	#[derive(Clone, PartialEq, Default)]
50	pub struct EmulatorState {
51	    pub registers: [u32; 8],
52	    pub prev_registers: [u32; 8],      // Changed last step (hot)
53	    pub prev_prev_registers: [u32; 8], // Changed 2 steps ago (warm)
54	    pub pc: u32,
55	    pub condition_flag: bool,
56	    pub is_halted: bool,
57	    pub led_value: u8,
58	    pub led_duty_cycle: f32, // 0.0 (always off) to 1.0 (always on) over Run
59	    pub led_on_count: u64,   // Instructions executed with LED on (cumulative during Run)
60	    pub instruction_count: u32,
61	    pub memory_low: SparseMemory,   // SRAM (0x000000-0x0FFFFF)
62	    pub memory_io_led: Vec<u8>,     // I/O: LED/Switch at 0xFF0000 (16 bytes)
63	    pub memory_io_uart: Vec<u8>,    // I/O: UART at 0xFF0100 (16 bytes)
64	    pub memory_stack: SparseMemory, // EBR/Stack (0xFEE000-0xFEEC00)
65	    pub program_end: u32,           // End of code+data region
66	    pub prev_memory_low: SparseMemory,
67	    pub prev_memory_io_led: Vec<u8>,
68	    pub prev_memory_io_uart: Vec<u8>,
69	    pub prev_memory_stack: SparseMemory,
70	    pub prev_prev_memory_low: SparseMemory,
71	    pub prev_prev_memory_io_led: Vec<u8>,
72	    pub prev_prev_memory_io_uart: Vec<u8>,
73	    pub prev_prev_memory_stack: SparseMemory,
74	    pub current_instruction: String,
75	    pub assembled_lines: Vec<String>,
76	    pub uart_output: String,
77	    pub trace_lines: Vec<String>,
78	}
79	
80	/// Wizard steps for progressive disclosure
81	#[derive(Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
82	pub enum WizardStep {
83	    Source,    // Rust source code
84	    Compile,   // MSP430 assembly output
85	    Translate, // COR24 assembly output
86	    Assemble,  // Assembled + debugger
87	}
88	
89	impl WizardStep {
90	    fn label(&self) -> &'static str {
91	        match self {
92	            WizardStep::Source => "Source",
93	            WizardStep::Compile => "Compile",
94	            WizardStep::Translate => "Translate",
95	            WizardStep::Assemble => "Assemble",
96	        }
97	    }
98	
99	    fn next(&self) -> Option<WizardStep> {
100	        match self {
101	            WizardStep::Source => Some(WizardStep::Compile),
102	            WizardStep::Compile => Some(WizardStep::Translate),
103	            WizardStep::Translate => Some(WizardStep::Assemble),
104	            WizardStep::Assemble => None,
105	        }
106	    }
107	
108	    fn action_label(&self) -> &'static str {
109	        match self {
110	            WizardStep::Source => "Compile",
111	            WizardStep::Compile => "Translate",
112	            WizardStep::Translate => "Assemble",
113	            WizardStep::Assemble => "",
114	        }
115	    }
116	
117	    fn action_tooltip(&self) -> &'static str {
118	        match self {
119	            WizardStep::Source => "Compile Rust to MSP430 assembly",
