   ============================================================================= */

.rust-wizard-layout {
    display: grid;
    grid-template-columns: 120px 160px 1fr;
    height: 100%;
    overflow: hidden;
}

/* Column 1: Sidebar with buttons and peripherals */
.wizard-sidebar {
    display: flex;
    flex-direction: column;
    padding: 6px;
    background: #1a1a2e;
    border-right: 1px solid #3d2e6b;
}

.wizard-buttons {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

.wizard-buttons button {
    width: 100%;
    padding: 8px;
    background: #2d1f4e;
    color: #c792ea;
    border: 1px solid #3d2e6b;
    border-radius: 4px;
    cursor: pointer;
    font-weight: bold;
    font-size: 0.75em;
    transition: all 0.2s;
}

.wizard-buttons button:hover {
    background: #3d2e6b;
    border-color: #c792ea;
}

.wizard-peripherals {
    margin-top: 24px;
    padding-top: 16px;
    border-top: 1px solid #3d2e6b;
}

.peripheral-section {
    margin-bottom: 16px;
}

.peripheral-label {
    color: #c792ea;
    font-size: 0.75em;
    font-weight: bold;
    margin-bottom: 8px;
}

.led-row-vertical {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    justify-content: center;
}

.led-hex {
    text-align: center;
    color: #0f0;
    font-family: 'Monaco', monospace;
    font-size: 0.75em;
    margin-top: 6px;
}

.switch-row-vertical {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    justify-content: center;
}

.switch-hex {
    text-align: center;
    color: #0ff;
    font-family: 'Monaco', monospace;
    font-size: 0.75em;
    margin-top: 6px;
}

.peripheral-status {
    color: #666;
    font-size: 0.7em;
    font-style: italic;
}

/* Column 2: Wizard steps */
.wizard-steps {
    display: flex;
    flex-direction: column;
    padding: 12px;
    background: #1e1836;
    border-right: 1px solid #3d2e6b;
}

.wizard-header-space {
    height: 12px;
}

.wizard-step {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 10px 12px;
    border-radius: 4px;
    margin-bottom: 4px;
    cursor: default;
    transition: all 0.2s;
}

.wizard-step.active {
    background: #2d1f4e;
    border: 1px solid #c792ea;
}

.wizard-step.completed {
    cursor: pointer;
}

.wizard-step.completed:hover {
    background: rgba(199, 146, 234, 0.1);
}

.wizard-step.completed .step-indicator {
    color: #4caf50;
}

.wizard-step.disabled {
    opacity: 0.4;
}

.step-indicator {
    font-size: 1em;
    width: 20px;
    text-align: center;
    color: #c792ea;
}

.step-label {
    color: #eee;
    font-size: 0.85em;
}

.wizard-action-btn {
    margin-top: 16px;
    padding: 10px 16px;
    background: #7c3aed;
    color: white;
    border: none;
    border-radius: 4px;
    font-weight: bold;
    font-size: 0.85em;
    cursor: pointer;
    transition: all 0.2s;
    animation: wizard-btn-glow 1.5s ease-in-out infinite;
}

@keyframes wizard-btn-glow {
    0%, 100% {
        box-shadow: 0 0 10px rgba(167, 139, 250, 0.7), 0 0 20px rgba(124, 58, 237, 0.5);
        transform: scale(1);
    }
    50% {
        box-shadow: 0 0 25px rgba(167, 139, 250, 1), 0 0 50px rgba(124, 58, 237, 0.9), 0 0 80px rgba(124, 58, 237, 0.6);
        transform: scale(1.03);
    }
}

.wizard-action-btn:hover {
    background: #6d28d9;
    /* Keep animation running on hover */
}

.wizard-spacer {
    flex: 1;
}

.wizard-exit-btn {
    margin-top: 8px;
    padding: 8px 12px;
    background: #6b7280;
    color: white;
    border: none;
    border-radius: 4px;
    font-size: 0.85em;
    font-weight: bold;
    cursor: pointer;
    transition: all 0.2s;
}

.wizard-exit-btn:hover {

