file.content:
    background: #4b5563;
}

/* Column 3: Notebook cells */
.notebook-cells {
    overflow-y: auto;
    padding: 12px;
    padding-bottom: calc(100vh - 150px); /* Allow any cell to scroll to top */
    scroll-behavior: smooth;
    background: #1a1a2e;
}

.editor-column {
    display: flex;
    flex-direction: column;
    min-width: 0;
    min-height: 0;
}

/* Toolbar above editor for Examples/Challenges buttons */
.editor-toolbar {
    display: flex;
    gap: 8px;
    padding: 4px 0;
}

.wizard-header-btn {
    padding: 4px 8px;
    text-align: center;
}

.toolbar-btn {
    background: #1e1836;
    color: #c792ea;
    border: 1px solid #3d2e6b;
    border-radius: 4px;
    padding: 5px 14px;
    font-size: 0.85em;
    font-weight: bold;
    cursor: pointer;
}

.toolbar-btn:hover {
    background: #2d1f4e;
    border-color: #7c3aed;
}

/* Notebook placeholder when no example loaded */
.notebook-placeholder {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 200px;
    background: #1e1836;
    border-radius: 5px;
    border: 2px dashed #3d2e6b;
    color: #888;
    font-size: 1em;
}

.notebook-cell {
    background: #1e1836;
    border-radius: 5px;
    margin-bottom: 12px;
    border: 1px solid #3d2e6b;
}

/* Debug cell needs visible overflow for native <select> dropdowns */
.notebook-cell:not(.notebook-cell-debug) {
    overflow: hidden;
}

.notebook-cell.collapsed {
    display: none;
}

.notebook-cell.minimized {
    max-height: 50px;
}

.cell-header {
    padding: 10px 12px;
    background: #2d1f4e;
    color: #ffd700;
    font-weight: bold;
    font-size: 1.05em;
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.cell-header-example {
    font-weight: bold;
    font-size: 0.95em;
    color: #ffd700;
    font-style: italic;
}

.cell-badge {
    background: #3d2e6b;
    color: #888;
    padding: 2px 8px;
    border-radius: 10px;
    font-size: 0.75em;
    font-weight: normal;
}

.cell-content {
    padding: 12px;
}

/* Code blocks in notebook cells - purple theme */
.rust-wizard-layout .code-block {
    background: #12101f;
    border: 1px solid #3d2e6b;
    font-size: 1.1em;
    max-height: none;
}

.rust-wizard-layout .rust-code {
    color: #f8a5c2;
}

.rust-wizard-layout .asm-code {
    color: #a5d6a7;
}

.rust-wizard-layout .hex-dump {
    color: #888;
}

