    font-size: 0.82em;
    cursor: pointer;
    transition: all 0.2s;
    animation: wizard-btn-glow 1.8s ease-in-out infinite;
}

@keyframes wizard-btn-glow {
    0%, 100% {
        box-shadow: 0 0 8px rgba(137, 180, 250, 0.5), 0 0 16px rgba(137, 180, 250, 0.3);
        transform: scale(1);
    }
    50% {
        box-shadow: 0 0 20px rgba(137, 180, 250, 0.8), 0 0 40px rgba(137, 180, 250, 0.5);
        transform: scale(1.02);
    }
}

.wizard-action-btn:hover {
    background: var(--lavender);
}

.wizard-spacer {
    flex: 1;
}

/* Column 3: Notebook cells */
.notebook-cells {
    overflow-y: auto;
    padding: 12px;
    padding-bottom: calc(100vh - 150px);
    scroll-behavior: smooth;
    background: var(--base);
}

.notebook-cell {
    background: var(--mantle);
    border-radius: 6px;
    margin-bottom: 12px;
    border: 1px solid var(--surface0);
    overflow: hidden;
}

.cell-header {
    padding: 8px 12px;
    background: var(--surface0);
    color: var(--yellow);
    font-weight: bold;
    font-size: 0.95em;
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.cell-header-example {
    font-weight: bold;
    font-size: 0.85em;
    color: var(--yellow);
    font-style: italic;
}

.cell-content {
    padding: 0;
}

/* --- Source editor (textarea + highlight overlay) --- */
.editor-container {
    position: relative;
    min-height: 300px;
    height: 50vh;
}

.editor-highlight,
.editor-textarea {
    position: absolute;
    inset: 0;
    margin: 0;
    padding: 12px;
    font-family: var(--mono);
    font-size: 14px;
    line-height: 1.5;
    border: none;
    white-space: pre;
    overflow: auto;
    tab-size: 2;
    word-wrap: normal;
}

.editor-highlight {
    background: var(--mantle);
    color: var(--text);
    pointer-events: none;
    z-index: 1;
}

.editor-highlight code {
    font-family: inherit;
    font-size: inherit;
    line-height: inherit;
}

.editor-textarea {
    background: transparent;
    color: transparent;
    caret-color: var(--text);
    resize: none;
    outline: none;
    z-index: 2;
    -webkit-text-fill-color: transparent;
}

.editor-textarea::selection {
    background: rgba(137, 180, 250, 0.25);
    -webkit-text-fill-color: transparent;
}

/* --- Syntax highlighting colors (Catppuccin Mocha) --- */
.hl-keyword {
    color: var(--mauve);
    font-weight: bold;
}

.hl-comment {
    color: var(--overlay1);
    font-style: italic;
}

.hl-string {
    color: var(--green);
}

.hl-number {
    color: var(--peach);
}

.hl-macro {
    color: var(--yellow);
    font-weight: bold;
}

.hl-asm {
    color: var(--red);
    font-weight: bold;
}

.hl-asm-text {
    color: var(--teal);
}

/* --- Notebook placeholder --- */
.notebook-placeholder {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 200px;
    background: var(--mantle);
    border-radius: 6px;
    border: 2px dashed var(--surface1);
    color: var(--overlay1);
    font-size: 1em;
}

/* --- Pipeline note --- */
.pipeline-note {
    padding: 12px;
    color: var(--overlay0);
    font-size: 0.8em;
    text-align: center;
}

/* --- File upload (hidden input + label) --- */
.file-upload-input {
    display: none;
}

.file-upload-label {
    display: block;
    width: 100%;
    padding: 7px 8px;
    background: var(--surface0);
    color: var(--blue);
    border: 1px solid var(--surface1);
    border-radius: 4px;
    cursor: pointer;
    font-family: var(--mono);
    font-weight: bold;
    font-size: 0.75em;
    text-align: center;
    transition: all 0.15s;
}

.file-upload-label:hover {
    background: var(--surface1);
    border-color: var(--blue);
}

